return p

local p = {}
p.getSpouse = function(frame) local spouse_input = mw.text.trim(frame.args[1] or "") if spouse_input == "FETCH_WIKIDATA" then -- get from wikidata local entity = mw.wikibase.getEntity() local out = {} for k, v in pairs(entity.claims.p26) do out[#out + 1] = "[[" .. mw.wikibase.sitelink("Q" .. v.mainsnak.datavalue.value["numeric-id"]) .. "]]" end -- TODO: hlist return return table.concat(out, ", ") else return spouse_input end end
